module dram_cell (  
    input wire [3:0] D,  
    input wire WE,  
    input wire CLK,  
    output reg [3:0] Q  
);  
    reg [3:0] obf_storage;  

    always @(posedge CLK) begin  
        if (WE)  
            obf_storage <= D;  
        else  
            Q <= obf_storage;  
    end  
endmodule
